def get_tier(rank):
    try:
        if isinstance(rank, (pd.Series, list, dict)):
            return None
        if pd.isna(rank):
            return None

        rank_val = int(float(rank))

        if rank_val < 1 or rank_val > 1000:
            return 0  

        return 11 - ((rank_val - 1) // 100 + 1)

    except (TypeError, ValueError):
        return None

